#include <bits/stdc++.h>
using namespace std;
const int N=1e5+5,M=3e5+5;
struct Edge{
	int u,v,w;
}edge[M];
struct Graph{
	int to,val;
};
bool cmp(Edge x,Edge y){
	return x.w<y.w;
}

int n,m,q,fa[N],f[N][15],deep[N],h[N][15];
vector<Graph> g[N];

int father(int x){
	return (fa[x]==x?x:fa[x]=father(fa[x]));
}

void dfs(int x){
	int len=g[x].size();
	for(int i=0;i<len;i++)
		if(!deep[g[x][i].to]){
			int v=g[x][i].to,w=g[x][i].val;
			deep[v]=deep[x]+1;
			f[v][0]=x,h[v][0]=w;
			for(int j=1;j<15;j++){
				f[v][j]=f[f[v][j-1]][j-1],h[v][j]=max(h[v][j-1],h[f[v][j-1]][j-1]);
				if(!f[v][j])
					break;
			}
			dfs(g[x][i].to);
		}
}

int LCA(int x,int y){
	if(deep[x]<deep[y])
		swap(x,y);
	int ans=0; 
	for(int i=14;i>=0;i--)
		if(deep[f[x][i]]>=deep[y])
			ans=max(ans,h[x][i]),x=f[x][i];
	if(x==y)
		return ans;
	for(int i=14;i>=0;i--)
		if(f[x][i] && f[y][i] && f[x][i]!=f[y][i])
			ans=max(ans,max(h[x][i],h[y][i])),x=f[x][i],y=f[y][i];
	ans=max(ans,max(h[x][0],h[y][0])),x=f[x][0],y=f[y][0];
	return ans;
}

int main(){
	scanf("%d%d",&n,&m);
	for(int i=0;i<m;i++)
		scanf("%d%d%d",&edge[i].u,&edge[i].v,&edge[i].w);
	scanf("%d",&q);
	for(int i=1;i<=n;i++)
		fa[i]=i;
	sort(edge,edge+m,cmp);
	for(int i=0;i<m;i++){
		int fu=father(edge[i].u),fv=father(edge[i].v);
		if(fu!=fv){
			g[edge[i].u].push_back({edge[i].v,edge[i].w});
			g[edge[i].v].push_back({edge[i].u,edge[i].w});
			fa[fv]=fu;
		}
	}
	for(int i=1;i<=n;i++)
		if(!deep[i]){
			deep[i]=1;
			dfs(i);
		}
	for(int i=0;i<q;i++){
		int a,b;
	    scanf("%d%d",&a,&b);
		if(father(a)!=father(b))
			printf("impossible\n");
		else
			printf("%d\n",LCA(a,b));
	}
	return 0;
}
